#include <bits/stdc++.h>
#define int long long
#define double long double
using namespace std;
int d[20][300000];
int n;
int w[20];
int m;
int up;
signed main() {
	ios::sync_with_stdio (0);
	cin.tie (0), cout.tie (0);
	cin >> n >> m;
	for (int i = 0; i < n; i++) {
		cin >> w[i];
	}
	up = pow (2, n);
	for (int i = 0; i < n; i++) {
		for (int j = 0; j <= up - 1; j++) {
			d[i][j] = 1e18;
		}
	}
	for (int i = 0; i < n; i++) {
		d[1][1 << i] = w[i];
	}
	for (int i = 0; i <= n; i++) {
		for (int j = 0; j <= up - 1; j++) {
			if (d[i][j] != 1e18) {
				for (int k = 0; k < n; k++) {
					if ((j & (1 << k)) != 0) {
						continue;
					}
					if (d[i][j] + w[k] <= m) {
						d[i][j | (1 << k)] = min (d[i][j | (1 << k)], d[i][j] + w[k]);
					} else {
						d[i + 1][j | (1 << k)] = min (d[i][j | (1 << k)], w[k]);
					}
				}
			}
		}
	}
	for (int i = 0; i <= n; i++) {
		if (d[i][up - 1] != 1e18) {
			cout << i;
			break;
		}
	}
	return 0;
}
